#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
void scan_bcao(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel for schedule(static)
  for (int64_t bid = 0; bid < nblocks; ++bid)
  {
    T temp[2 * N];

    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    for (int thid = 0; thid < N / 2; ++thid) {
      int a = thid;
      int b = a + (N / 2);
      int oa = OFFSET(a);
      int ob = OFFSET(b);

      temp[a + oa] = gi[a];
      temp[b + ob] = gi[b];
    }

    int offset = 1;
    for (int d = N >> 1; d > 0; d >>= 1)
    {
      for (int thid = 0; thid < N / 2; ++thid)
      {
        if (thid < d)
        {
          int ai = offset * (2 * thid + 1) - 1;
          int bi = offset * (2 * thid + 2) - 1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          temp[bi] += temp[ai];
        }
      }
      offset *= 2;
    }

    temp[N - 1 + OFFSET(N - 1)] = 0;
    for (int d = 1; d < N; d *= 2)
    {
      offset >>= 1;
      for (int thid = 0; thid < N / 2; ++thid)
      {
        if (thid < d)
        {
          int ai = offset * (2 * thid + 1) - 1;
          int bi = offset * (2 * thid + 2) - 1;
          ai += OFFSET(ai);
          bi += OFFSET(bi);
          T t = temp[ai];
          temp[ai] = temp[bi];
          temp[bi] += t;
        }
      }
    }

    for (int thid = 0; thid < N / 2; ++thid) {
      int a = thid;
      int b = a + (N / 2);
      int oa = OFFSET(a);
      int ob = OFFSET(b);
      go[a] = temp[a + oa];
      go[b] = temp[b + ob];
    }
  }
}

template<typename T, int N>
void scan(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata)
{
  #pragma omp parallel for schedule(static)
  for (int64_t bid = 0; bid < nblocks; ++bid)
  {
    T temp[N];

    auto gi = g_idata + bid * N;
    auto go = g_odata + bid * N;

    int offset = 1;
    for (int thid = 0; thid < N / 2; ++thid) {
      temp[2 * thid]     = gi[2 * thid];
      temp[2 * thid + 1] = gi[2 * thid + 1];
    }

    for (int d = N >> 1; d > 0; d >>= 1)
    {
      for (int thid = 0; thid < N / 2; ++thid)
      {
        if (thid < d)
        {
          int ai = offset * (2 * thid + 1) - 1;
          int bi = offset * (2 * thid + 2) - 1;
          temp[bi] += temp[ai];
        }
      }
      offset *= 2;
    }

    temp[N - 1] = 0;
    for (int d = 1; d < N; d *= 2)
    {
      offset >>= 1;
      for (int thid = 0; thid < N / 2; ++thid)
      {
        if (thid < d)
        {
          int ai = offset * (2 * thid + 1) - 1;
          int bi = offset * (2 * thid + 2) - 1;
          T t = temp[ai];
          temp[ai] = temp[bi];
          temp[bi] += t;
        }
      }
    }

    for (int thid = 0; thid < N / 2; ++thid) {
