#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <omp.h>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time - t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  #pragma omp parallel for collapse(2)
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y * Lx + x;
      int v0p = y * Lx + (x + 1) % Lx;
      int v0m = y * Lx + (Lx + x - 1) % Lx;
      int vp0 = ((y + 1) % Ly) * Lx + x;
      int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
      out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

void dev_lapl_iter(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  const int N = Lx * Ly;
  #pragma omp parallel for
  for (int i = 0; i < N; i++) {
    int x = i % Lx;
    int y = i / Lx;
    int v00 = y * Lx + x;
    int v0p = y * Lx + (x + 1) % Lx;
    int v0m = y * Lx + (Lx + x - 1) % Lx;
    int vp0 = ((y + 1) % Ly) * Lx + x;
    int vm0 = ((Ly + y - 1) % Ly) * Lx + x;
    out[v00] = norm * in[v00] + delta * (in[v0p] + in[v0m] + in[vp0] + in[vm0]);
  }
}

int main(int argc, char *argv[]) {

  if (argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  float *buffer = (float *)malloc(sizeof(float) * Lx * Ly);
  float *h_out = (float *)malloc(sizeof(float) * Lx * Ly);
  float *h_in  = (float *)malloc(sizeof(float) * Lx * Ly);
  float *d_res = (float *)malloc(sizeof(float) * Lx * Ly);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float) * Lx * Ly);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_in, *d_out;
  d_in = (float *)malloc(sizeof(float) * Lx * Ly);
  d_out = (float *)malloc(sizeof(float) * Lx * Ly);
  memcpy(d_in, buffer, sizeof(float) * Lx * Ly);

  double t0 = stop_watch(0);

  for (i = 0; i < niter; i++) {
    dev_lapl_iter(d_out, d_in, xdelta, xnorm, Lx, Ly);
    std::swap(d_out, d_in);
  }

  t0 = stop_watch(t0) / (double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  memcpy(d_res, d_in, sizeof(float) * Lx * Ly);

  bool ok = true;
  for (i = 0; i < Lx * Ly; i++) {
    if (fabs(h_in[i] - d_res[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_res[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(d_in);
  free(d_out);
  free(buffer);
  free(h_out);
  free(h_in);
  free(d_res);
  return 0;
}

